-- Seed data: inserts the two test question banks (modeler / leadership)
-- verbatim from content/modeler-test.json and content/leadership-test.json.
-- Safe to re-run: upserts on conflict.

insert into public.tests (id, title, duration_minutes, schema)
values (
  'modeler',
  'SCORE — Modeler / Senior Modeler Assessment',
  45,
  $modeler_schema${"testId":"modeler","program":"BIMstream SCORE","programFullName":"Situational Competency & Organizational Readiness Evaluation","title":"SCORE — Modeler / Senior Modeler Assessment","durationMinutes":45,"audience":"BIM Modelers and Senior Modelers","description":"Purely HR/behavioral instrument, 30 questions at ~90 seconds each. Technical/software skill is assessed separately (technical test + Personal Interview), so this test carries no technical items at all. Weighted for an individual-contributor role: Team Play, Communication, and Problem-Solving get the most questions; Leadership is present at a lighter weight to spot early potential; Dispute Resolution, Organizational Mindset, and Ethics carry small dedicated quotas but ethics-concern flags can surface on any question, not just the dedicated ones.","topicWeights":{"TP":7,"CM":6,"PS":6,"LD":4,"DR":3,"OM":2,"ET":2},"sections":[{"type":"situational_judgment","instructions":"Choose the option that best reflects how you would actually act. There is no single 'correct' answer — pick the one truest to your instinct.","questions":[{"id":"M-TP-01","topic":"TP","prompt":"A new teammate joins mid-project, unfamiliar with your studio's model standards, while you're on a tight deadline yourself. What do you do?","options":[{"text":"Point them to the standards documentation and tell them to work through it independently, since you can't spare the time right now.","trait_deltas":{"TP":-2,"CM":-1}},{"text":"Spend fifteen to twenty minutes walking them through the key standards now, then check back in once they've had time to apply them.","trait_deltas":{"TP":2,"CM":1,"LD":1}},{"text":"Ask a colleague who has more bandwidth today to handle the onboarding instead, so the new teammate still gets proper guidance.","trait_deltas":{"TP":-1}},{"text":"Assume they'll ask if they run into trouble, and focus your attention on your own deadline for now.","trait_deltas":{"TP":-2,"CM":-1}}]},{"id":"M-TP-02","topic":"TP","prompt":"A colleague on another discipline's team is overloaded and asks for informal help outside your assigned tasks. What do you do?","options":[{"text":"Decline the request politely, explaining that it falls outside your assigned tasks and you need to stay focused on your own workload.","trait_deltas":{"TP":-1}},{"text":"Jump in and help as much as they need, quietly absorbing the extra hours yourself without flagging the risk to your own deadline.","trait_deltas":{"TP":1,"PS":-1,"CM":-1}},{"text":"Offer a specific, time-boxed amount of help and let your own lead know about the trade-off so priorities stay visible.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Say you'll help 'later' to sound supportive, without actually committing to a concrete time or scope for that help.","trait_deltas":{"TP":-1,"CM":-1}}]},{"id":"M-TP-03","topic":"TP","prompt":"In a team meeting, credit for a successful clash-resolution effort gets attributed mostly to someone who did less of the actual work. What do you do?","options":[{"text":"Let it go and say nothing in the moment, deciding the credit mix-up isn't worth the awkwardness of raising it.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Correct the record right there in the meeting, emphasizing your own role firmly so people know what you actually did.","trait_deltas":{"TP":-1,"CM":-1,"DR":-1}},{"text":"Calmly mention the fuller picture afterward, factually crediting everyone who contributed to the fix, including your own part.","trait_deltas":{"TP":2,"CM":2}},{"text":"Say nothing in the meeting, but vent about it privately to other teammates afterward instead of addressing it directly.","trait_deltas":{"TP":-2,"CM":-1}}]},{"id":"M-TP-04","topic":"TP","prompt":"You notice a teammate quietly struggling, and their slipping work is starting to threaten the team's shared deadline. What do you do?","options":[{"text":"Stay focused on your own tasks, reasoning that their workload and any slippage is really their own responsibility to manage.","trait_deltas":{"TP":-2,"LD":-1}},{"text":"Flag their struggling to your manager right away, without first talking it through with the teammate themselves.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Check in with them privately and directly, ask what's going on, and offer specific, practical support to help them catch up.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Quietly absorb their unfinished work yourself, without mentioning it to them, your manager, or anyone else on the team.","trait_deltas":{"TP":0,"PS":-1,"CM":-1}}]},{"id":"M-TP-05","topic":"TP","prompt":"Your project wins client praise, but a teammate who contributed less publicly claims most of the credit in front of others. What's your reaction?","options":[{"text":"Push back on their claim right there in front of everyone, correcting them sharply in the moment.","trait_deltas":{"TP":-1,"DR":-1,"CM":-1}},{"text":"Let it go entirely and never bring it up with anyone, even though the credit-grabbing genuinely bothers you.","trait_deltas":{"TP":0,"CM":-1}},{"text":"Calmly and factually acknowledge the whole team's contribution afterward, including your own part, without turning it into a confrontation.","trait_deltas":{"TP":2,"CM":2}},{"text":"Note the injustice quietly and start claiming extra credit yourself in future projects, telling yourself it just evens things out.","trait_deltas":{"TP":-2,"ET":-1}}]},{"id":"M-TP-06","topic":"TP","prompt":"Helping another discipline hit their deadline would require you to slightly adjust your own schedule, at some real cost to you. What's your approach?","options":[{"text":"Refuse the request outright, reasoning that their deadline pressure isn't really your problem to solve or accommodate.","trait_deltas":{"TP":-2}},{"text":"Agree right away without asking any questions, and don't mention the real cost this shift will have on your own schedule.","trait_deltas":{"TP":1,"PS":-1,"CM":-1}},{"text":"Discuss the trade-off honestly with your lead and the other discipline, then agree on a compromise that actually works for both.","trait_deltas":{"TP":2,"CM":2,"PS":1}},{"text":"Agree to help, but reluctantly, and let your irritation about the cost show throughout the rest of the interaction.","trait_deltas":{"TP":-1,"CM":-1}}]},{"id":"M-TP-07","topic":"TP","prompt":"You disagree with a decision your team made collectively in a meeting you weren't part of. What do you do?","options":[{"text":"Disagree quietly with the decision and just implement it your own preferred way instead, without telling anyone.","trait_deltas":{"TP":-2,"CM":-1}},{"text":"Go along with it outwardly in front of the team, but vent your real objections to others behind the scenes.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Raise your concern constructively with the team or decision-maker afterward, then fully support the decision once it's been discussed.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Go along with the decision quietly, never voicing your view even briefly in the meeting when it was still open.","trait_deltas":{"TP":0,"CM":-1}}]},{"id":"M-CM-01","topic":"CM","prompt":"You need to explain a complex clash issue to non-technical stakeholders (e.g. the client's facilities team) who don't understand BIM jargon. What's your approach?","options":[{"text":"Stick with the full technical terminology in your explanation, since you feel that's the most precise way to describe it.","trait_deltas":{"CM":-2}},{"text":"Simplify heavily using plain analogies, avoid jargon entirely, and check they've actually understood before you move on to anything else.","trait_deltas":{"CM":2,"PS":1}},{"text":"Ask a colleague who's better at translating technical detail to handle the explanation for you instead.","trait_deltas":{"CM":-1}},{"text":"Give a quick technical summary and move on to the next topic, regardless of whether they actually followed along.","trait_deltas":{"CM":-2}}]},{"id":"M-CM-02","topic":"CM","prompt":"An important coordination decision was made verbally in a meeting. What do you do to make sure nothing gets lost?","options":[{"text":"Assume everyone will remember the verbal decision accurately, and skip writing anything down or circulating a summary afterward.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Write a brief but clear summary of what was decided and share it with everyone involved right after the meeting ends.","trait_deltas":{"CM":2,"PS":1}},{"text":"Write detailed notes for your own records only, keeping them private rather than sharing them with the rest of the team.","trait_deltas":{"CM":-1}},{"text":"Wait for someone else on the team to take responsibility for writing up the meeting minutes instead of doing it yourself.","trait_deltas":{"CM":-1,"LD":-1}}]},{"id":"M-CM-03","topic":"CM","prompt":"A teammate's message about a coordination issue is unclear and could mean two very different things. What do you do?","options":[{"text":"Guess at what they most likely meant based on context, and proceed with the work without checking your assumption first.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Send a quick clarifying question right away and wait for their answer before you proceed with any of the work.","trait_deltas":{"CM":2,"PS":1}},{"text":"Proceed with whichever interpretation is easiest for your own schedule, regardless of what they most likely actually intended.","trait_deltas":{"CM":-2,"ET":-1}},{"text":"Leave the message unanswered for now and wait for them to follow up if it's actually important.","trait_deltas":{"CM":-1}}]},{"id":"M-CM-04","topic":"CM","prompt":"Partway through a task, you realize the brief you were given was ambiguous and you've made an assumption that might be wrong. What do you do?","options":[{"text":"Keep pushing forward on your current approach and simply hope that your original assumption turns out to be correct.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Reach out early to confirm your assumption is correct, before you invest much more time building on top of it.","trait_deltas":{"CM":2,"PS":2}},{"text":"Finish the task using your own assumption, and only mention the ambiguity later if someone happens to ask about it.","trait_deltas":{"CM":-1,"PS":-1}},{"text":"Redo the task several different ways to cover every possible interpretation, without checking in with anyone about which is right.","trait_deltas":{"CM":-1,"PS":-1}}]},{"id":"M-CM-05","topic":"CM","prompt":"A client questions why a deliverable took longer than the timesheet estimate implied. What's the best response?","options":[{"text":"Tell them it was due to unspecified 'technical issues,' without going into any further detail about what actually happened.","trait_deltas":{"CM":-1}},{"text":"Give a clear, honest breakdown of what the extra time actually involved and why, framed constructively rather than defensively.","trait_deltas":{"CM":2,"ET":2,"PS":1}},{"text":"Explain that the delay was mostly caused by a teammate's part of the work, without owning your own share of it.","trait_deltas":{"CM":-2,"ET":-1,"DR":-2}},{"text":"Avoid answering the question directly and steer the conversation toward a different, less uncomfortable topic instead.","trait_deltas":{"CM":-2,"ET":-1}}]},{"id":"M-CM-06","topic":"CM","prompt":"Your manager's instructions for a task conflict with what the client previously told you directly. What do you do?","options":[{"text":"Follow your manager's instructions as given, without mentioning that they conflict with what the client told you earlier.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Follow the client's version instead, since they said it directly to you, without flagging the conflict back to your manager.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Point out the discrepancy to your manager as soon as you notice it, so it gets clarified before you proceed.","trait_deltas":{"CM":2,"PS":2}},{"text":"Pick whichever version seems technically easier to execute right now, without raising the conflict with either party.","trait_deltas":{"CM":-2,"PS":-1}}]},{"id":"M-PS-01","topic":"PS","prompt":"Two disciplines' models disagree on a critical dimension by 200mm, discovered the day before an issue-for-construction deadline. What's your first move?","options":[{"text":"Pick whichever number intuitively looks more correct to you, and proceed with issuing the set on that basis.","trait_deltas":{"PS":-2,"ET":-1}},{"text":"Escalate immediately to your lead with both models and screenshots, flagging it as blocking until the two disciplines jointly resolve it.","trait_deltas":{"PS":2,"CM":2,"LD":1}},{"text":"Issue the set as scheduled anyway, adding a note flagging the discrepancy for someone to look at afterward.","trait_deltas":{"PS":-1,"ET":-1}},{"text":"Hold off saying anything and wait to see whether someone else on the team notices the discrepancy first.","trait_deltas":{"PS":-2,"LD":-2,"CM":-2}}]},{"id":"M-PS-02","topic":"PS","prompt":"You realize you misjudged the time a modeling task would take and are now behind, with the deadline in two days. What do you do?","options":[{"text":"Say nothing about being behind and just work faster, skipping some of your usual QA checks to try to catch up.","trait_deltas":{"PS":-1,"ET":-1,"CM":-1}},{"text":"Inform your lead early with a realistic revised estimate, and ask together about reprioritizing scope or bringing in extra support.","trait_deltas":{"PS":2,"CM":2,"ET":1,"LD":1}},{"text":"Keep working quietly and wait until the actual deadline arrives to explain to anyone what happened and why.","trait_deltas":{"CM":-2,"ET":-1,"PS":-1}},{"text":"When explaining the delay, attribute it mainly to an unclear brief at the start rather than your own time estimate.","trait_deltas":{"CM":-1,"ET":-1,"LD":-1}}]},{"id":"M-PS-03","topic":"PS","prompt":"A software malfunction during a critical work session right before a deadline costs you an hour of unsaved work. What do you do?","options":[{"text":"Panic in the moment and immediately announce to the whole team that the deadline is now impossible to hit.","trait_deltas":{"PS":-2,"CM":-1}},{"text":"Quickly assess what's actually lost, try any alternate recovery options available, and give your lead a realistic revised estimate right away.","trait_deltas":{"PS":2,"CM":1,"LD":1}},{"text":"Quietly try to redo the lost work on your own, without adjusting the estimate or telling anyone what happened.","trait_deltas":{"PS":-1,"CM":-1}},{"text":"Blame the software malfunction openly to the team and just wait around for someone else to give you instructions.","trait_deltas":{"PS":-1,"CM":-1}}]},{"id":"M-PS-04","topic":"PS","prompt":"You're given conflicting information from two sources about a critical requirement (e.g. ceiling height) for the same space. What's your approach?","options":[{"text":"Pick whichever source happens to be more convenient for the work you've already done, without checking further.","trait_deltas":{"PS":-2,"ET":-1}},{"text":"Cross-check both sources against the master documents or BEP, and escalate to your lead if it's still unresolved after that.","trait_deltas":{"PS":2,"CM":1}},{"text":"Use whichever number was given to you most recently, regardless of how reliable that particular source actually is.","trait_deltas":{"PS":-1}},{"text":"Split the difference and proceed with an average of the two numbers, without actually verifying either one.","trait_deltas":{"PS":-2}}]},{"id":"M-PS-05","topic":"PS","prompt":"A task turns out to be more complex than expected, and you're not sure of the best technical approach. What do you do?","options":[{"text":"Take your best guess at an approach and just hope it works out well enough once you get further in.","trait_deltas":{"PS":-2}},{"text":"Research standard approaches first, and if you're still unsure, ask a more experienced colleague before committing significant time to it.","trait_deltas":{"PS":2,"TP":1,"CM":1}},{"text":"Pick the first approach that comes to mind and keep going with it, even as new information suggests otherwise.","trait_deltas":{"PS":-1}},{"text":"Quietly avoid picking up the task and hope that someone else on the team ends up handling it instead.","trait_deltas":{"PS":-2,"LD":-1}}]},{"id":"M-PS-06","topic":"PS","prompt":"You're assigned a task with insufficient information to complete it accurately, and the person who could clarify is unavailable for a day. The deadline is tomorrow. What do you do?","options":[{"text":"Make your best guess at the missing information and proceed with the task, without documenting it or telling anyone.","trait_deltas":{"PS":-2,"CM":-1}},{"text":"Make a reasonable, clearly-documented assumption, work cautiously on the lower-risk parts first, and flag the open question once the person is back.","trait_deltas":{"PS":2,"CM":2}},{"text":"Stop all work on the task entirely and wait until the person who can clarify it is available again.","trait_deltas":{"PS":-1,"LD":-1}},{"text":"Ask a random colleague who also doesn't actually know the answer, and treat their guess as if it were confirmed fact.","trait_deltas":{"PS":-1}}]},{"id":"M-LD-01","topic":"LD","prompt":"A newer teammate keeps making the same mistake, creating rework for you. Even though you're not their manager, what do you do?","options":[{"text":"Quietly redo their work yourself each time it happens, since that feels easier than having an awkward conversation about it.","trait_deltas":{"LD":-1,"TP":-1}},{"text":"Report the recurring mistake directly to management, asking that the teammate be formally reprimanded for the repeated rework it causes.","trait_deltas":{"LD":0,"CM":-1,"DR":-1}},{"text":"Sit down with them, walk through the correct method together, and check their next few submissions before escalating to anyone else.","trait_deltas":{"LD":2,"CM":2,"TP":1}},{"text":"Point out the mistake openly during the coordination meeting so the rest of the team is aware it keeps happening.","trait_deltas":{"LD":-1,"CM":-2}}]},{"id":"M-LD-02","topic":"LD","prompt":"During a chaotic coordination crunch, no one has clearly taken charge of triaging what to fix first. What do you do, even without formal authority?","options":[{"text":"Hold back from stepping in and wait for someone more senior to take charge of the triage instead.","trait_deltas":{"LD":-2}},{"text":"Step in to suggest a simple priority order for the group to align around right away, without waiting to be asked.","trait_deltas":{"LD":2,"PS":1,"CM":1}},{"text":"Focus only on getting your own piece sorted and leave it to the rest of the group to figure out priorities.","trait_deltas":{"LD":-1}},{"text":"Take charge of the whole triage yourself and start assigning priorities without checking in with anyone else first.","trait_deltas":{"LD":-1,"TP":-1}}]},{"id":"M-LD-03","topic":"LD","prompt":"You disagree with a modeling standard your studio uses and believe your own method is better. What do you do?","options":[{"text":"Quietly switch to using your own preferred method instead, since you're confident it works better than the current standard.","trait_deltas":{"LD":-1,"CM":-1}},{"text":"Raise it with your lead or BIM manager, with reasoning and evidence, while continuing to follow the current standard during the discussion.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Complain to your colleagues informally that the standard feels outdated, without ever raising it formally with anyone who could change it.","trait_deltas":{"LD":-1,"CM":-2}},{"text":"Follow the existing standard as instructed, without ever bringing up your concern with your lead or BIM manager.","trait_deltas":{"LD":-1}}]},{"id":"M-LD-04","topic":"LD","prompt":"A junior colleague asks you, an experienced modeler, whether they're ready to take on more responsibility. What do you do?","options":[{"text":"Give a quick, generic 'sure, you're ready' answer and move the conversation on to something else fairly fast.","trait_deltas":{"LD":-1,"CM":-1}},{"text":"Take the time to give specific, honest feedback based on what you've actually observed in their work, and suggest one concrete next step.","trait_deltas":{"LD":2,"CM":2,"TP":1}},{"text":"Redirect them to ask their manager instead, since that feels like a more appropriate conversation for you to have.","trait_deltas":{"LD":-1}},{"text":"Give a softened, overly positive answer rather than an honest one, mainly to avoid hurting their feelings right now.","trait_deltas":{"LD":-1,"CM":-1,"ET":-1}}]},{"id":"M-DR-01","topic":"DR","prompt":"In a coordination meeting, a structural engineer insists a beam position is fixed and MEP must reroute around it — even though that reroute would violate minimum ceiling clearance required by code. What do you do?","options":[{"text":"Agree in the meeting to avoid conflict and go along with the reroute, despite knowing it creates a code clearance issue.","trait_deltas":{"PS":-1,"ET":-1,"DR":-1}},{"text":"Push back firmly, insisting structural has to move the beam, without offering the group any alternative options to consider.","trait_deltas":{"DR":-1,"CM":-1}},{"text":"Clearly flag the code clearance conflict with technical justification, and propose two or three alternatives for the group to evaluate together.","trait_deltas":{"PS":2,"CM":2,"DR":2,"LD":1}},{"text":"Stay quiet about the code conflict during the meeting itself, and raise the concern privately with your manager afterward instead.","trait_deltas":{"PS":0,"CM":-1,"DR":-1,"LD":-1}}]},{"id":"M-DR-02","topic":"DR","prompt":"During a late-night coordination call under deadline pressure, a colleague is visibly stressed and starts snapping at others. What do you do?","options":[{"text":"Ignore the tension entirely and stay focused on your own part of the call, deciding it isn't your problem to manage.","trait_deltas":{"CM":-1,"DR":-1}},{"text":"Snap back sharply in the moment to defend the person being criticized, matching the stressed colleague's tone.","trait_deltas":{"CM":-1,"DR":-1}},{"text":"Acknowledge the stress calmly, redirect the conversation back to the specific issue, and suggest a short break if things stay tense.","trait_deltas":{"CM":2,"DR":2,"LD":1}},{"text":"Say nothing to the colleague during the call, but report their behavior to management right afterward instead.","trait_deltas":{"CM":-1,"DR":-1}}]},{"id":"M-DR-03","topic":"DR","prompt":"Two teammates on your project openly disagree about the right modeling approach in front of you and ask you to weigh in. What do you do?","options":[{"text":"Stay carefully neutral and avoid picking a side, even though you privately think one approach is clearly more correct.","trait_deltas":{"DR":-1,"PS":-1}},{"text":"Give your honest technical opinion based on the actual merits of each approach, while staying respectful of both people's perspectives.","trait_deltas":{"DR":2,"CM":2,"PS":1}},{"text":"Side with whichever teammate happens to be more senior, regardless of which approach actually has the stronger technical merits.","trait_deltas":{"DR":-2}},{"text":"Escalate the disagreement straight to your lead, without first offering your own technical opinion to either teammate.","trait_deltas":{"DR":-1}}]},{"id":"M-OM-01","topic":"OM","prompt":"A recurring coordination issue keeps causing delays across multiple projects, not just yours. What's the best individual response as a modeler (not yet a manager)?","options":[{"text":"Keep manually solving the issue each time it resurfaces on your own projects, without looking at the wider pattern.","trait_deltas":{"OM":-1,"PS":0}},{"text":"Document the recurring pattern and its impact across projects, and proactively suggest to your lead that it's worth fixing at the source.","trait_deltas":{"OM":2,"PS":2,"CM":1}},{"text":"Assume it's someone more senior's job to notice the pattern across projects, and say nothing about it yourself.","trait_deltas":{"OM":-1,"PS":-1}},{"text":"Complain about the recurring issue informally to teammates, without ever raising it as a formal process concern to your lead.","trait_deltas":{"OM":-1,"CM":-1}}]},{"id":"M-OM-02","topic":"OM","prompt":"Your studio is under resourcing pressure across several projects at once, and you finish your own task early. What do you do?","options":[{"text":"Consider your own part of the work done, and simply wait for your next task to be assigned to you.","trait_deltas":{"OM":-1}},{"text":"Proactively check with your lead whether another project or teammate could use your help, given the studio-wide resourcing crunch right now.","trait_deltas":{"OM":2,"TP":1,"LD":1}},{"text":"Use the unexpected spare time on personal tasks of your own, without mentioning to anyone that you finished early.","trait_deltas":{"OM":-2}},{"text":"Sit tight and wait to be told what to do next, rather than asking your lead if help is needed elsewhere.","trait_deltas":{"OM":-1}}]},{"id":"M-ET-01","topic":"ET","prompt":"At 6pm you discover an error in the shared central model that will affect three other disciplines' work if not fixed tonight. Fixing it means at least 2 unplanned overtime hours. What do you do?","options":[{"text":"Log off at your normal time and plan to mention the error in tomorrow's coordination meeting, since no one asked you to stay late.","trait_deltas":{"PS":-1,"CM":-1,"LD":-1}},{"text":"Fix it tonight yourself, but just leave the extra hours off your timesheet this once so it doesn't look like you're padding it.","trait_deltas":{"PS":1,"CM":-2,"ET":-2},"flag":"ethics_concern"},{"text":"Notify your coordinator right away about the issue and its downstream impact, offer to fix it tonight, and log your actual hours honestly.","trait_deltas":{"PS":2,"CM":2,"ET":2,"LD":1}},{"text":"Go ahead and fix it tonight on your own, but don't bring it up with anyone unless somebody happens to ask.","trait_deltas":{"PS":1,"CM":-1,"ET":-1}}]},{"id":"M-ET-02","topic":"ET","prompt":"Your manager asks you to sign off on a coordination model as 'clash-free,' but you know a few unresolved clashes remain in a low-visibility area. What do you do?","options":[{"text":"Sign off as 'clash-free' since your manager asked you to, reasoning that it's technically their call to make, not yours.","trait_deltas":{"ET":-2},"flag":"ethics_concern"},{"text":"Decline to sign off as requested, and clearly document the remaining clashes and their risk before anyone makes a final decision.","trait_deltas":{"ET":2,"CM":2,"LD":1}},{"text":"Sign off as asked to keep things moving, but quietly mention the unresolved clashes to a colleague just so someone else knows.","trait_deltas":{"ET":-1,"CM":-1},"flag":"ethics_concern"},{"text":"Hold off responding to your manager for now, hoping the sign-off question somehow resolves itself or someone else handles it.","trait_deltas":{"ET":-1,"LD":-1}}]}]}]}$modeler_schema$::jsonb
)
on conflict (id) do update set
  title = excluded.title,
  duration_minutes = excluded.duration_minutes,
  schema = excluded.schema,
  updated_at = now();

insert into public.tests (id, title, duration_minutes, schema)
values (
  'leadership',
  'SCORE — Assistant Manager / Manager Assessment',
  45,
  $leadership_schema${"testId":"leadership","program":"BIMstream SCORE","programFullName":"Situational Competency & Organizational Readiness Evaluation","title":"SCORE — Assistant Manager / Manager Assessment","durationMinutes":45,"audience":"Assistant Managers and Managers overseeing BIM coordination teams","description":"Purely HR/behavioral instrument, 30 questions at ~90 seconds each. Technical/software skill is assessed separately (technical test + Personal Interview), so this test carries no technical items at all. Weighted for a managerial role: Leadership gets the most questions, Communication and Team Play next, then Problem-Solving; Dispute Resolution and Organizational Mindset carry smaller dedicated quotas (though still higher than at the modeler level, reflecting real managerial exposure), and Ethics is a minimal but always-active dimension — ethics-concern flags can surface on any question, not just the 2 dedicated ones.","topicWeights":{"LD":7,"CM":6,"TP":5,"PS":5,"DR":3,"OM":2,"ET":2},"sections":[{"type":"situational_judgment","instructions":"Choose the option that best reflects how you would actually act. There is no single 'correct' answer — pick the one truest to your instinct.","questions":[{"id":"L-LD-01","topic":"LD","prompt":"A junior staff member makes a significant error that reaches the client before being caught. As team lead, what's your response?","options":[{"text":"Correct the mistake quietly yourself and hold off telling the client, since raising it might create embarrassment that doesn't seem worth the risk.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Explain to the client that the junior staff member was responsible, keeping the focus off your own role in overseeing the work.","trait_deltas":{"CM":-2,"LD":-2,"DR":-1,"ET":-1}},{"text":"Own the error with the client, share the correction and prevention plan, then address the root cause privately and constructively with the person involved.","trait_deltas":{"LD":2,"CM":2,"ET":2}},{"text":"Decide the mistake is serious enough that the junior staff member should be let go from the team without further discussion.","trait_deltas":{"LD":-2,"ET":-1}}]},{"id":"L-LD-02","topic":"LD","prompt":"A major clash is discovered right before a permit submission and your team is panicking. What's your leadership approach?","options":[{"text":"Step in and take over every task yourself, feeling that's the only way to be confident everything gets handled correctly under pressure.","trait_deltas":{"LD":-1}},{"text":"Stay calm, quickly triage the issue, delegate clear ownership of specific parts, and set a tight but realistic timeline with regular check-ins.","trait_deltas":{"LD":2,"PS":2,"CM":2}},{"text":"Step back and let the team work through it on their own, mainly to avoid coming across as micromanaging during a stressful moment.","trait_deltas":{"LD":-2,"PS":-1}},{"text":"Before diving into the fix, spend some time figuring out who's responsible for the clash so accountability is clear going forward for everyone.","trait_deltas":{"LD":-2,"DR":-2,"CM":-1}}]},{"id":"L-LD-03","topic":"LD","prompt":"A talented team member consistently disrespects deadlines but produces excellent technical work. How do you manage this?","options":[{"text":"Let the missed deadlines slide since the technical work is strong enough that it doesn't seem worth risking friction over timing.","trait_deltas":{"LD":-1,"PS":-1}},{"text":"Address the deadline pattern directly and specifically, set clear expectations and consequences, while still acknowledging their genuine technical strength.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Call out the repeated lateness in front of the whole team so everyone understands deadlines are taken seriously here.","trait_deltas":{"CM":-2,"LD":-1,"DR":-1}},{"text":"Quietly shift their tasks over to other people instead of raising the deadline pattern directly with them in conversation.","trait_deltas":{"CM":-2,"LD":-1}}]},{"id":"L-LD-04","topic":"LD","prompt":"A new Assistant Manager under you is eager but making decisions above their authority level, causing confusion on the team. How do you handle it?","options":[{"text":"Correct their decisions openly in front of the team whenever they overstep, so everyone sees where the real authority sits.","trait_deltas":{"LD":-2,"CM":-1,"DR":-1}},{"text":"Have a direct, supportive conversation clarifying decision boundaries, mentor them on judgment, and reinforce those boundaries consistently over time.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Say nothing directly to them, but quietly override the decisions yourself whenever you happen to notice them stepping too far.","trait_deltas":{"LD":-1,"CM":-2}},{"text":"Pull back their decision-making authority without much explanation, figuring the situation will sort itself out over time.","trait_deltas":{"LD":-1,"CM":-1}}]},{"id":"L-LD-05","topic":"LD","prompt":"Productivity data (billed hours vs. deliverables) shows one team member underperforming for several months. What's your approach as manager?","options":[{"text":"Quietly adjust that person's billed hours after the fact, reasoning it's simpler than raising the performance issue with them or the client.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Have a private, evidence-based performance conversation, identify root causes, set a clear improvement plan with support, then follow up.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Let the underperformance continue for now, since raising it feels like it would create an uncomfortable conversation you'd rather avoid.","trait_deltas":{"LD":-2,"PS":-1}},{"text":"Quietly shift their work over to others rather than having a direct conversation with them about the performance gap.","trait_deltas":{"LD":-1,"CM":-1}}]},{"id":"L-LD-06","topic":"LD","prompt":"You're promoted to manage former peers. One of them resents reporting to you now. What do you do?","options":[{"text":"Hold back from giving them much direction for now, hoping the resentment fades naturally if you just keep the peace.","trait_deltas":{"LD":-2}},{"text":"Have an honest, direct conversation acknowledging the shift, clarify expectations, and earn credibility through fair, consistent leadership over time.","trait_deltas":{"LD":2,"CM":2,"TP":1}},{"text":"Assert your new authority firmly and early, making clear that reporting lines have changed regardless of how they feel about it.","trait_deltas":{"LD":-1,"CM":-1,"DR":-1}},{"text":"Mention their attitude to your own manager rather than addressing it with them directly yourself in the moment.","trait_deltas":{"LD":-1}}]},{"id":"L-LD-07","topic":"LD","prompt":"A high-priority client project needs a lead assigned from your team, and two capable people want the role. How do you decide?","options":[{"text":"Give the role to whoever has pushed for it most persistently, since that seems like the clearest signal of interest.","trait_deltas":{"LD":-1}},{"text":"Assess based on project fit, availability, and development opportunity, explain the reasoning transparently to both, and offer the other a near-term opportunity.","trait_deltas":{"LD":2,"CM":2,"ET":1}},{"text":"Step back from deciding and let the two of them work out between themselves who should take the lead role.","trait_deltas":{"LD":-1}},{"text":"Choose based on your own personal preference, without bothering to explain that reasoning clearly to either person involved.","trait_deltas":{"LD":-1,"CM":-1}}]},{"id":"L-CM-01","topic":"CM","prompt":"A client is unhappy about slipped deadlines and threatens to escalate to your director. What's your approach?","options":[{"text":"Hold off on returning the client's calls for now, until you have more concrete progress or better news to share with them.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Reach out to the client proactively, acknowledge the delay honestly, and walk them through a realistic recovery plan with firm dates.","trait_deltas":{"CM":2,"LD":2,"ET":1}},{"text":"When speaking with the client, frame the delay as mostly driven by dependencies on other disciplines and subcontractors outside your direct control.","trait_deltas":{"CM":-1,"ET":-1,"DR":-1}},{"text":"Give the client a recovery date that feels reassuring in the moment, even though you're not fully confident the team can hit it.","trait_deltas":{"ET":-1,"CM":-1,"PS":-1}}]},{"id":"L-CM-02","topic":"CM","prompt":"A client asks directly whether your team can meet an aggressive deadline you privately doubt is realistic. What do you say?","options":[{"text":"Tell the client yes for now to avoid disappointing them, planning to work out the actual feasibility with the team later.","trait_deltas":{"ET":-1,"CM":-1,"PS":-1}},{"text":"Give an honest assessment of the risks and what would need to be true to hit the date, then propose realistic options.","trait_deltas":{"CM":2,"ET":2,"PS":2,"LD":1}},{"text":"Tell the client directly that the deadline isn't realistic, without offering any alternative path or compromise in the moment.","trait_deltas":{"CM":-1,"PS":-1}},{"text":"Keep your answer vague and noncommittal, hoping to avoid pinning yourself down until you have more clarity later.","trait_deltas":{"CM":-2}}]},{"id":"L-CM-03","topic":"CM","prompt":"A client says your own communication style in status meetings is 'too technical and hard to follow.' How do you respond?","options":[{"text":"Brush off the feedback, reasoning that technical accuracy in the meetings matters more than making things simpler for the client.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Take the feedback seriously, adjust your communication approach for that audience, and check in regularly for ongoing feedback afterward.","trait_deltas":{"CM":2,"LD":1,"PS":1}},{"text":"Get a little defensive and explain to the client why they should try to follow your explanations more closely.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Hand off future client meetings to someone else on the team rather than working on adjusting your own approach.","trait_deltas":{"CM":-1,"LD":-1}}]},{"id":"L-CM-04","topic":"CM","prompt":"Budget cuts mean reducing your team's software license count, which will slow some work. How do you communicate this internally?","options":[{"text":"Announce the license cut without much explanation, figuring the team just needs to adjust to the new reality quickly.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Explain the business context honestly, involve the team in prioritizing the affected workflows, and set realistic expectations with stakeholders.","trait_deltas":{"CM":2,"LD":2,"PS":1}},{"text":"Frame the cut as something imposed vaguely by 'management above,' rather than owning the decision yourself as their leader.","trait_deltas":{"CM":-1,"LD":-1}},{"text":"Hold off telling the team about the change until the reduced license count actually starts causing visible problems.","trait_deltas":{"CM":-2,"LD":-1}}]},{"id":"L-CM-05","topic":"CM","prompt":"You need to deliver difficult news to the whole team — a valued project was cancelled or scope significantly reduced. How do you approach it?","options":[{"text":"Send the team a short email about the change and steer clear of further discussion unless someone directly asks.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Hold a live conversation, explain the context honestly, acknowledge the impact on the team, and answer their questions directly.","trait_deltas":{"CM":2,"LD":2}},{"text":"Let word of the change spread informally through the team rather than addressing it directly yourself in a meeting.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Downplay how significant the change really is when talking to the team, even if that stretches the truth somewhat.","trait_deltas":{"CM":-1,"ET":-1}}]},{"id":"L-CM-06","topic":"CM","prompt":"Two people on your team interpret your instructions for a task completely differently, causing duplicated/conflicting effort. What do you do?","options":[{"text":"Point out to the two of them that they should have asked more clarifying questions before running with their own interpretation.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Take ownership of the miscommunication, clarify the task immediately, and adjust your future instructions to be more explicit going forward.","trait_deltas":{"CM":2,"LD":1,"PS":1}},{"text":"Leave the two of them to sort out the conflicting interpretations on their own rather than stepping in yourself.","trait_deltas":{"CM":-1,"LD":-1}},{"text":"Just go with whichever interpretation is more convenient at this point, without circling back to explain the mix-up.","trait_deltas":{"CM":-2}}]},{"id":"L-TP-01","topic":"TP","prompt":"Two previously siloed discipline sub-teams under you rarely collaborate and duplicate effort. How do you build a stronger sense of shared team identity?","options":[{"text":"Leave the two sub-teams as they are for now, since each one is still delivering its own work reasonably well.","trait_deltas":{"TP":-2}},{"text":"Create shared touchpoints like joint reviews and shared recognition, and actively model cross-team collaboration yourself in day-to-day work.","trait_deltas":{"TP":2,"LD":2,"CM":1}},{"text":"Merge the two sub-teams formally on paper, without really addressing the underlying culture that's kept them siloed apart.","trait_deltas":{"TP":-1}},{"text":"Hold off addressing the disconnect unless a client actually complains about duplicated effort or inconsistent coordination between the two groups.","trait_deltas":{"TP":-1,"LD":-1}}]},{"id":"L-TP-02","topic":"TP","prompt":"A star performer on your team refuses to mentor or share knowledge with others, protecting their own indispensability. What do you do?","options":[{"text":"Leave them be for now, since their individual output is strong enough that it seems not worth pushing on.","trait_deltas":{"TP":-1,"LD":-1}},{"text":"Talk with them directly about how mentoring factors into how you evaluate senior-level contributions, and set up structured chances for them to mentor.","trait_deltas":{"TP":2,"LD":2,"CM":1}},{"text":"Call them out in front of the team for not being enough of a team player about sharing knowledge.","trait_deltas":{"TP":-1,"CM":-2}},{"text":"Quietly shift mentoring responsibilities onto other people instead of addressing the underlying behavior with them directly yourself.","trait_deltas":{"TP":-1,"LD":-1}}]},{"id":"L-TP-03","topic":"TP","prompt":"Your team must absorb extra scope with no extra time, and morale is already stretched. How do you rally them?","options":[{"text":"Just assign the extra scope to the team and trust everyone to manage it on top of their current workload.","trait_deltas":{"TP":-2,"LD":-1}},{"text":"Be transparent about the situation, involve the team in deciding how to divide the load fairly, and acknowledge their extra effort.","trait_deltas":{"TP":2,"LD":2,"CM":2}},{"text":"Take on most of the extra work yourself quietly, rather than asking an already-stretched team to absorb more of it.","trait_deltas":{"TP":-1,"LD":-1}},{"text":"Promise the team rewards for the extra push that you're not entirely sure you'll actually be able to deliver.","trait_deltas":{"TP":-1,"ET":-1}}]},{"id":"L-TP-04","topic":"TP","prompt":"A remote or satellite-office team member feels excluded from key decisions made in the main office. What do you do?","options":[{"text":"Assume it's a fairly minor issue, since the remote team member still ends up receiving the final decisions either way.","trait_deltas":{"TP":-2}},{"text":"Actively include them in relevant discussions going forward and check in regularly on how included they actually feel.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Suggest that they bring it up themselves in a meeting if the exclusion is really bothering them that much.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Hold off addressing it unless their output actually starts to suffer as a visible result of feeling excluded.","trait_deltas":{"TP":-1}}]},{"id":"L-TP-05","topic":"TP","prompt":"A Junior and a Senior on the same task are competitive with each other rather than collaborative, and it's affecting quality. What do you do?","options":[{"text":"Let the two of them work it out between themselves, since a bit of healthy competition can push quality up too.","trait_deltas":{"TP":-1,"LD":-1}},{"text":"Set clear shared goals and structure the task so their success is interdependent, addressing the competitive dynamic directly with both.","trait_deltas":{"TP":2,"LD":2,"DR":1}},{"text":"Move them onto separate tasks going forward instead of addressing the competitive dynamic between them directly in conversation.","trait_deltas":{"TP":0,"LD":-1}},{"text":"Reprimand both of them for the friction without spending much time understanding what's actually driving the competitive dynamic.","trait_deltas":{"TP":-1,"CM":-1}}]},{"id":"L-PS-01","topic":"PS","prompt":"A team lead under you wants to skip a QA review step to hit a deadline, 'just this once.' What's your call?","options":[{"text":"Approve skipping QA this one time, reasoning the deadline pressure justifies it and it's unlikely to cause real problems.","trait_deltas":{"ET":-1,"PS":-1}},{"text":"Say no, but work with the team to find a genuinely faster path to complete QA properly rather than skipping it.","trait_deltas":{"ET":2,"PS":2,"LD":1}},{"text":"Approve the request without much discussion, since you generally trust the lead's judgment on calls like this one.","trait_deltas":{"ET":-1,"PS":-1}},{"text":"Say no to skipping QA, but don't offer any alternative way to still try to meet the deadline.","trait_deltas":{"LD":-1,"PS":-1}}]},{"id":"L-PS-02","topic":"PS","prompt":"A client's facilities team insists on a design change that conflicts with a code-compliance issue your BIM team identified. What do you do?","options":[{"text":"Go ahead with the client's requested change, reasoning that they're paying for the project and it's ultimately their call.","trait_deltas":{"ET":-2,"PS":-1},"flag":"ethics_concern"},{"text":"Clearly document the code conflict and risk, get the decision formally recorded, and escalate internally and to the client's leadership before implementing anything.","trait_deltas":{"ET":2,"PS":2,"CM":2,"LD":1}},{"text":"Implement the change as requested, but quietly have a junior document it as a CYA measure rather than raising it with the client formally.","trait_deltas":{"ET":-1,"CM":-1}},{"text":"Refuse to discuss the code conflict with the client any further, treating the matter as effectively already closed.","trait_deltas":{"CM":-2,"DR":-1}}]},{"id":"L-PS-03","topic":"PS","prompt":"Your team can hit the deadline OR maintain full quality, but not both, and the client hasn't been made aware of this trade-off. What's your approach as manager?","options":[{"text":"Quietly cut some quality to hit the deadline, reasoning the client doesn't need to know about the trade-off being made.","trait_deltas":{"PS":-2,"ET":-1,"CM":-1},"flag":"ethics_concern"},{"text":"Present the trade-off honestly to the client and let them decide which matters more, or negotiate for more time or resources.","trait_deltas":{"PS":2,"CM":2,"ET":1}},{"text":"Miss the deadline without giving the client any advance warning, hoping the quality outcome will speak for itself later.","trait_deltas":{"PS":-2,"CM":-2}},{"text":"Push the team to work unsustainable hours trying to hit both targets, without really addressing the systemic scheduling issue.","trait_deltas":{"PS":-1,"LD":-1}}]},{"id":"L-PS-04","topic":"PS","prompt":"Two competing internal priorities — a strategic new client and an existing client's ongoing work — both need your best people at the same time. How do you resolve the resourcing conflict?","options":[{"text":"Give the new strategic client whatever resourcing they ask for, since landing them well feels like the higher priority.","trait_deltas":{"PS":-1,"OM":-1}},{"text":"Evaluate objectively against business priorities, communicate the trade-offs transparently to both stakeholders, and look for creative resourcing options first.","trait_deltas":{"PS":2,"OM":1,"CM":1}},{"text":"Default to whichever client is currently pushing hardest or complaining the loudest about needing more resourcing support.","trait_deltas":{"PS":-2}},{"text":"Split your best people evenly across both, regardless of what each project's actual staffing needs really are.","trait_deltas":{"PS":-1}}]},{"id":"L-PS-05","topic":"PS","prompt":"A long-standing process at your studio clearly isn't working anymore as the studio has grown, but changing it will be disruptive short-term. What do you do?","options":[{"text":"Leave the process alone for now, since changing something that's embedded this deeply feels risky and disruptive short-term.","trait_deltas":{"PS":-1,"OM":-1}},{"text":"Propose and pilot a change with a clear plan to manage the short-term disruption, gathering team input before rolling it out.","trait_deltas":{"PS":2,"OM":2,"LD":1}},{"text":"Force the change through right away without piloting it or consulting the team about how it'll actually affect their work.","trait_deltas":{"PS":-1,"TP":-1}},{"text":"Point out repeatedly that the process is outdated, without actually putting together a concrete proposal to fix it.","trait_deltas":{"PS":-1}}]},{"id":"L-DR-01","topic":"DR","prompt":"Two department leads under you have an ongoing personal conflict that's starting to affect team morale and coordination quality. What do you do?","options":[{"text":"Stay out of it for now, treating the tension between the two leads as more of a personal matter.","trait_deltas":{"LD":-2,"DR":-2}},{"text":"Meet with each separately, then together, understand the root causes, establish clear working agreements, and follow up over time.","trait_deltas":{"LD":2,"DR":2,"CM":2}},{"text":"Address the tension between them openly in a team meeting so everyone understands it needs to stop right away.","trait_deltas":{"DR":-1,"CM":-1,"LD":-1}},{"text":"Transfer one of them to a different team fairly quickly, without really digging into what's driving the conflict.","trait_deltas":{"LD":-1,"DR":-1}}]},{"id":"L-DR-02","topic":"DR","prompt":"A dispute escalates between your team and another team (led by a peer manager) over who's responsible for a coordination failure that affected the client. What do you do?","options":[{"text":"Frame the coordination failure to the client as mainly the other team's responsibility, to protect your own team's standing.","trait_deltas":{"DR":-2,"CM":-1}},{"text":"Meet privately with the peer manager first, focus on root cause and preventing recurrence rather than blame, then align on a joint message.","trait_deltas":{"DR":2,"CM":2,"LD":1}},{"text":"Avoid engaging directly with the other manager and let the client draw their own conclusions about what happened.","trait_deltas":{"DR":-2}},{"text":"Escalate the disagreement straight to senior leadership rather than attempting to resolve it peer-to-peer with the other manager first.","trait_deltas":{"DR":-1,"LD":-1}}]},{"id":"L-DR-03","topic":"DR","prompt":"Two of your direct reports have a disagreement about technical approach that's becoming personal rather than professional. What do you do?","options":[{"text":"Let the two of them work it out, since stepping in might make it look like you're taking sides.","trait_deltas":{"DR":-2,"LD":-1}},{"text":"Intervene early, separate the technical disagreement from the personal friction, mediate a resolution, and address the interpersonal tension directly.","trait_deltas":{"DR":2,"LD":2,"CM":1}},{"text":"Side with whichever one is more senior in the discussion, mainly to bring the disagreement to a quicker end.","trait_deltas":{"DR":-2}},{"text":"Reassign one of them to a different task, mainly as a way to sidestep dealing with the conflict directly.","trait_deltas":{"DR":-1,"LD":-1}}]},{"id":"L-OM-01","topic":"OM","prompt":"You notice a pattern where multiple projects at your studio hit avoidable delays for the same root-cause reason. What's your response as manager?","options":[{"text":"Handle each project's delay on its own as it comes up, without really stepping back to look at the pattern.","trait_deltas":{"OM":-2,"PS":-1}},{"text":"Bring the recurring pattern to studio leadership, push for a root-cause fix, and follow up on whether it actually moves outcomes across projects.","trait_deltas":{"OM":2,"LD":1,"PS":1}},{"text":"Assume other managers are likely noticing the same pattern too and will probably raise it themselves eventually.","trait_deltas":{"OM":-2}},{"text":"Mention the pattern informally in passing to a few people, without really pushing for a concrete fix afterward.","trait_deltas":{"OM":-1}}]},{"id":"L-OM-02","topic":"OM","prompt":"A decision that's good for your team's short-term numbers would be mildly harmful to the studio's reputation with a client relationship that matters long-term. What do you do?","options":[{"text":"Prioritize your team's short-term numbers, reasoning that's mainly what you're measured on day to day as a manager.","trait_deltas":{"OM":-2,"ET":-1}},{"text":"Weigh the long-term studio and client relationship appropriately, even if it means a weaker short-term outcome, and explain that reasoning upward.","trait_deltas":{"OM":2,"LD":1,"ET":1}},{"text":"Make the short-term-favorable choice for your team without really raising or considering the longer-term angle with anyone.","trait_deltas":{"OM":-2}},{"text":"Avoid making the call for now and hope the situation somehow resolves itself without your direct involvement.","trait_deltas":{"OM":-1,"LD":-1}}]},{"id":"L-ET-01","topic":"ET","prompt":"Senior management asks you to reduce hours reported to a client without reducing the actual work required, to preserve a fee cap. What do you do?","options":[{"text":"Go along with it since it's a direct instruction from senior management, and questioning it doesn't feel worth the friction.","trait_deltas":{"ET":-2,"LD":-1},"flag":"ethics_concern"},{"text":"Push back clearly, explain the ethical and legal risk of misreporting hours, and propose alternatives like scope renegotiation or an efficiency review.","trait_deltas":{"ET":2,"LD":2,"CM":1}},{"text":"Go along with the instruction for now, but quietly keep your own private record of it in case questions come up later.","trait_deltas":{"ET":-1,"LD":-1},"flag":"ethics_concern"},{"text":"Quietly decide not to follow the instruction, without ever actually raising your concerns about it directly with management.","trait_deltas":{"CM":-1,"LD":-1}}]},{"id":"L-ET-02","topic":"ET","prompt":"You discover a deliverable sent to a client last week contained a significant, uncaught modeling error affecting cost estimates. What do you do?","options":[{"text":"Hold off saying anything for now, to see whether the client happens to notice the error on their own first.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Proactively notify the client as soon as possible, explain the correction clearly, and review internal QA to prevent recurrence.","trait_deltas":{"ET":2,"CM":2,"LD":2,"PS":1}},{"text":"Quietly fix the error in the next deliverable, without flagging that the earlier version had actually contained a mistake.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"When informing the client, attribute the error mainly to the software or an external vendor rather than your own team.","trait_deltas":{"ET":-1,"CM":-1}}]}]}]}$leadership_schema$::jsonb
)
on conflict (id) do update set
  title = excluded.title,
  duration_minutes = excluded.duration_minutes,
  schema = excluded.schema,
  updated_at = now();
